var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>챔버 도시관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>チェンバー都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is an announcement from Chamber City Management.</color>","TWN":"<color=#ffd34c>密室城市管理局通知。</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN_02"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 도심 전역에서 침식체가 출몰하고 있습니다.</color>","JPN":"<color=#ffd34c>現在、都市全域にて侵食体が出現中。</color>","ENG":"<color=#ffd34c>Currently, C.O.s are appearing across the entire city.</color>","TWN":"<color=#ffd34c>目前，整個市中心皆有侵蝕體出沒。</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최고 등급 재난 경보가 발령되었으니, 도시에 계신 시민 여러분은 신속하게 대피하시길 바랍니다.</color>","JPN":"<color=#ffd34c>最高ランクの災難警報が発令されました。市民の皆さんは迅速に避難してください。</color>","ENG":"<color=#ffd34c>The highest-level disaster alert has been issued. All citizens in the city are to evacuate immediately.</color>","TWN":"<color=#ffd34c>已發布最高等級災難警報，請位於城市的各位市民盡快撤離。</color>"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아아아악–!!","JPN":"きゃあああー！！","ENG":"Kyaaaah–!!","TWN":"呃啊啊啊啊–！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"헬프 미! SOS! 이머전시, 메이데이, 이대로 죽고 싶지 않아아아–––!!","JPN":"ヘルプミー！ SOS！　エマージェンシー、メーデー、このまま死にたくないぃぃぃ───！！","ENG":"Help me! SOS! Emergency, mayday! I don't wanna die like this–––!!","TWN":"救命！SOS！緊急，Mayday，我不想就這樣死掉–––！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"괜찮으신가요?","JPN":"大丈夫ですか？","ENG":"Are you all right?","TWN":"妳還好嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"허억… 이게… 괜찮아 보이는… 허억…….","JPN":"はあっ……これが……大丈夫そうに見え……はあっ……","ENG":"*Huff...* D-does... this look– *Huff...*","TWN":"呼呃…那個…我看起來好嗎…呼呃……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저, 주제넘지만…….","JPN":"あの、大変恐縮ですが……","ENG":"I know it's presumptuous, but...","TWN":"雖、雖然很冒昧……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"비스트 타입 침식체는 정면보다 하복부가 약한 편이니, 파고드는 편이 좋다고 생각해요.","JPN":"ビーストタイプの侵食体は正面より下腹部が弱いので、もうちょっと踏み込むほうがいいと思います。","ENG":"Beast-type C.O.s are weaker in the lower abdomen than head-on. You should dive in low.","TWN":"但野獸類型侵蝕體的下腹比正面還弱，我認為鑽進去會比較好。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"민서. 여긴 미쳤어요. 당장 빠져나가야 한다고요…!!","JPN":"ヒミコさん、ここはダメです。今すぐ逃げないと……！！","ENG":"Minseo, this place is insane. We need to get out, now...!!","TWN":"旼序，這裡瘋了，我們要馬上脫離…！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"응? 민서, 어디 있어요?","JPN":"うん？　ヒミコさん、どこですか？","ENG":"Huh? Minseo, where are you?","TWN":"嗯？旼序，妳在哪裡？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아아아악–!! 민서 양––––!!!!","JPN":"きゃああああー！！　ヒミコさぁぁぁん────！！！","ENG":"Kyaaaah–!! Minseo––––!!!!","TWN":"呃啊啊啊啊–！！旼序小姐––––！！！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"나는 벌레… 침식체님의 먹이…….","JPN":"ヒミコは虫……侵食体さんの餌……","ENG":"I'm a bug... fodder for the C.O.s...","TWN":"我是蟲子…侵蝕體的糧食……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"사지뼈의 정령님, 부디 안 아프게 부서져주세요…….","JPN":"四肢の精霊さん、どうか痛くないように砕けてください……","ENG":"O spirits of my limb bones, please break me without pain...","TWN":"四肢骨的精靈，請讓我無痛粉碎……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"워, 워. 하늘 덮은 먹구름 떼에 도망치는 건 내 하드보일드함이랑은 맞지 않지.","JPN":"やれやれ。空を覆う暗雲から逃げるなんて、私のハードボイルドさには似合わないな。","ENG":"Whoa there. Fleeing beneath a sky of black clouds isn't my hard-boiled style.","TWN":"哦、哦，逃到覆蓋天空的烏雲堆裡，不符合我的冷酷無情。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L30_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"적장의 목을 베었으니 술잔 가득 봄 햇살을 비추시게, 친구.","JPN":"敵将の首は切り落とした。盃いっぱい春の日差しを照らそうじゃないか、友よ。","ENG":"I've taken the enemy leader's head, friend. So let our cups brim with spring sunlight.","TWN":"既然砍下了敵將的頭，就讓酒杯映照滿滿的春光吧，朋友。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"1종짜리 하나 잡아놓고 뭘 꺼드럭대는 건가요…….","JPN":"第1種を1体倒しただけで何格好つけてるんですか……","ENG":"You felled a measly Category 1 and you're grandstanding...","TWN":"抓了一個1類有什麼好自以為是的……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그나마 덜 무섭게 죽을 기회였는데, 이젠 가망이 없어요…….","JPN":"さっき怖くない死に方ができるチャンスだったのに、もう無理です……","ENG":"That was my chance to die less painfully. Now we're doomed...","TWN":"本來是個至少不會死得這麼可怕的機會，現在沒希望了……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"중장님. 3중대가 고위 관료분들의 대피를 무사히 끝마쳤다고 합니다.","JPN":"中将。第3中隊が高位官僚たちを無事避難させたとのことです。","ENG":"Lieutenant General, 3rd Company reports the senior officials have been evacuated safely.","TWN":"中將，3中隊已經順利完成高層官員的撤離工作。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 거리의 침식체도 순탄하게 정리되어 가고 있는 듯해.","JPN":"ああ、街の侵食体も順調に片付いている。","ENG":"Good. The C.O.s on the street are being cleared smoothly, too.","TWN":"好，街上的侵蝕體整頓工作似乎也進行得很順利。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만… 이상하군.","JPN":"だが……妙だな。","ENG":"But... something's odd.","TWN":"但是…真奇怪。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"예? 그게 무슨 말씀이십니까?","JPN":"はい？　どういうことですか？","ENG":"Ma'am? What do you mean?","TWN":"嗯？那是什麼意思？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이번 일은 북방합의체가 관리국과 합중국에 협력을 요청했네.","JPN":"今回の件は、北方合意体から管理局と合衆国に協力を求めてきた件だ。","ENG":"The Northern Union asked the Administration and the States for cooperation this time.","TWN":"這次的事北方和議會向管理局跟合眾國請求合作。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런데 경보 발령 후 수 시간이 지났음에도… 우리 쪽에 지나칠 정도로 피해가 적군.","JPN":"だが、警報発令から数時間が経ったにもかかわらず……我々の被害が異常に少ない。","ENG":"Yet hours after the alert... casualties on our side are suspiciously low.","TWN":"但即使警報發布後過了好幾個小時…我們這邊受到的損害還是非常小。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"하지만 중장님. 이전 최고 등급 재난 역시 침식체에 대한 피해는 적었습니다.","JPN":"ですが中将。以前起きた最高ランクの災難でも、侵食体による被害の規模は大きくありませんでした。","ENG":"But ma'am, during the last highest-level disaster, damage from C.O.s was low as well.","TWN":"不過中將，以前最高等級災難對侵蝕體造成的損害也很小。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"챔버의 대균열은 지하에 있기까지 하니, 지상 쪽 피해는 적지 않겠습니까?","JPN":"それにチェンバーの大亀裂は地下にある分、地上の被害は少なくて当然ではないでしょうか？","ENG":"Chamber's Grand Dimension Crevice is underground, so surface damage should be limited, right?","TWN":"密室的大峽谷在地下，所以地面的損害應該不小吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대균열 확장은 부차적인 문제일 뿐. 우리가 대비한 건 세계를 멸망시킬 재난 현상일세.","JPN":"大亀裂の拡張はあくまで付随的な問題にすぎない。我々が備えているのは、世界を滅ぼす災難現象だ。","ENG":"The Grand Dimension Crevice expansion is secondary. We prepared for a calamity that could end the world.","TWN":"大峽谷擴張只是次要問題，我們要應對的是讓世界滅亡的災難現象。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 그 현상이 확정적으로 일어날 미래였다는 걸 생각하면, 어쩌면…….","JPN":"そしてその現象が確定的に起こる未来だということを考えると、もしかしたら……","ENG":"And considering that future was supposedly certain, maybe...","TWN":"而且想到那個現象是未來確定會發生的事，也許……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이건 군용 기밀 회선? 갑자기 무슨 일이지?","JPN":"これは……軍用機密回線？　急に何事だ？","ENG":"A military secure line? What's this about?","TWN":"這是軍用機密線路？突然是怎麼回事？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L16_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"바, 방어선의 공병부대로부터 보고입니다!","JPN":"ぼ、防衛線の工兵部隊から報告します！","ENG":"R-report from engineers on the defense line!","TWN":"防、防線工兵部隊報告！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"CSE레벨 급상승…! 현재 도심 일부 지역에 3등급 침식지대가–.","JPN":"CSEレベルが急上昇……！　現在、都心の一部地域にレベル3の侵食地帯が……","ENG":"CSE levels are spiking...! Parts of the city have now become a level 3 Corrupted Area–","TWN":"CSE等級急遽上升…！目前市中心部分地區3級侵蝕地帶–"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"아니, 레벨4? 이, 이건……!!","JPN":"いや、レベル4？　こ、これは……！！","ENG":"No, level 4?! Th-this is...!!","TWN":"等等，等級4？這、這是……！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DELTA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L20_1","type":"dialog","speaker":"DELTA_NPC_NULL_NULL","text":{"KOREA":"커헉…!?","JPN":"かはっ……！！","ENG":"Kuh...!","TWN":"咳呃…！？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이런……!","JPN":"しまった……！","ENG":"Damn it...!","TWN":"天哪……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"작전팀 전원, 긴급 회선으로 마리아 안토노프가 전한다!","JPN":"作戦チーム全員に緊急回線にてマリア・アントノフから伝える！","ENG":"All units, this is Maria Antonov on the emergency channel!","TWN":"作戰組全員，瑪麗亞·安東諾夫以緊急線路告知！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"현재 도심의 일부 지역으로부터 CSE 레벨의 급상승을 확인했다.","JPN":"現在、都心の一部地域からCSEレベルの急上昇を確認した。","ENG":"A CSE level spike has been confirmed in several sectors.","TWN":"目前已確認市中心部分地區CSE等級急遽上升。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카운터를 제외한 전 인원은 모든 작업을 중단하고 즉시 CSE 방호복을 착용하도록!","JPN":"カウンター以外の全人員はすべての作業を中断し、直ちにCSE防護服を着るように！","ENG":"All non-Counters, stop what you're doing and don CSE protective suits immediately!","TWN":"除了制裁者外的全體人員停止所有作業，立即著用CSE防護服。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"반복한다. 전 인원은 방호복 착용 후, 즉시 이터니움 실드의 잔량을 확인해라!","JPN":"繰り返す。全人員は防護服を着用し、エタニウムシールドの残量を確認したまえ！","ENG":"I repeat. Suit up, then check your remaining Eternium shield charge at once!","TWN":"再說一次，全體人員著用防護服後，立即確認永恆之金盾餘量！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대균열 쪽에도 지원을 보낼 테니, 우선–.","JPN":"大亀裂側にも支援を送る。まずは……","ENG":"I'll dispatch support to the Grand Dimension Crevice side. First–","TWN":"大峽谷那邊也會派人支援，首先–"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"중장님. 하늘에서 식별 불가의 침식체가 다수 접근해오고 있습니다!","JPN":"中将。空から識別不可の侵食体が多數接近中です！","ENG":"Lieutenant General! Multiple unidentified C.O.s approaching from the sky!","TWN":"中將，天上有許多無法識別的侵蝕體正在接近！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저 모습. 관리국 데이터베이스에서 본 침식체와 유사한 형태예요……!!","JPN":"あの姿、管理局のデータベースで見た侵食体と類似しています……！！","ENG":"Their silhouettes match forms I've seen in the Administration database...!!","TWN":"那個樣子，是跟在管理局資料庫裡看過的侵蝕體相似的形態……！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"덧없는 발버둥은 더 이상 아무 의미도 없다.","JPN":"無駄な足掻きはもう無意味だ。","ENG":"Futile thrashing has no meaning anymore.","TWN":"無謂的掙扎不再有任何意義。"},"stage":{"bg":"MAINSTREAM_124010","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"죽음은 곧 자비이자 해방, 너희가 누릴 수 있는 마지막 은총일지니.","JPN":"死は慈悲であり解放。貴様らが享受できる最後の恩寵であろう。","ENG":"Death is mercy and release. The last grace you wretches will know.","TWN":"死亡是慈悲也是解放，是你們能享受的最後恩寵。"},"stage":{"bg":"MAINSTREAM_124010","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"미물들은 머리를 조아리고, 무릎을 꿇어 그분의 뜻을 찬미하라.","JPN":"微物どもはひれ伏し、あの方の思し召しを賛美せよ。","ENG":"Vermin, bow your heads, kneel, and praise her will.","TWN":"渺小的人類磕頭下跪，讚美他的旨意吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_PHASECHANGE"},{"id":"L42_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"왕께서 당도하실 길을 닦기 위해… 우리가 친히 이곳에 임하였도다.","JPN":"王の進まれる道を整えるため……我々はここに降臨した。","ENG":"We ourselves have come to pave the way... for the queen's arrival.","TWN":"為了替王鋪整道路…我們親自來到這裡。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"제길! 어떻게 된 거야? 아까부터 장비가 죄다 먹통이잖아!","JPN":"くそ！　どうなってるんだ？　さっきから装備がまったく動かない！","ENG":"Damn it! What's happening? None of our gear is working!","TWN":"該死！怎麼回事？裝備從剛才開始全都失效了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"이곳의 기기는 정상 가동 중이다. 문제가 있다면 외부 쪽이겠지.","JPN":"ここの機器は正常に稼働している。問題があるとしたら外部の方だろう。","ENG":"All devices here are nominal. If there's an issue, it's external.","TWN":"這裡的機器正常運轉中，有問題的話，應該是在外部吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"설명을 바란 게 아니야! 이대로면 작전이고 나발이고 죄다 끝이라고!","JPN":"説明を求めてるんじゃない！　このままだと作戦はおろか、全部おしまいになっちまう！","ENG":"I didn't ask for an explanation! At this rate the whole op is toast!","TWN":"我不是要你解釋！這樣下去管他作戰還什麼鬼，全都結束了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이렇게 된 이상 내가 현장으로 직접 가겠어!","JPN":"こうなったら、俺が直接現場に行く！","ENG":"I've got no other choice! I'm going to the site myself!","TWN":"既然這樣，我要親自去一趟現場！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"불가능하다. 카운터가 아닌 넌, 현장에 도착하는 순간 피폭될 거야.","JPN":"不可能だ。カウンターではないあなたは、現場に着いた途端被爆する。","ENG":"Negative. You're not a Counter. Step outside and you'll be irradiated instantly.","TWN":"不可能，你不是制裁者，一到現場就會立刻遭受輻射。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그게 무슨 소리야? 여기서 멀쩡한데 밖이라고 대수겠나?","JPN":"どういうことだ？　ここで無事なら外も変わらないんじゃないか？","ENG":"What are you saying? We're fine in here so how bad can it be out there?","TWN":"那是什麼意思？我在這裡好端端的，外面有什麼大不了？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"아니, 본부가 안전한 건 잔여 이터니움을 활용해 실드량을 극대화했기 때문이다.","JPN":"いいや、本部が安全なのは、残りのエタニウムを活用してシールド量を極限まで増やしているからだ。","ENG":"HQ is safe because we maximized the shield with the remaining Eternium.","TWN":"不，本部之所以安全，是因為運用剩餘的永恆之金將遮蔽量極大化。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"현재 CSE 레벨을 고려하면, 일반인이 맨몸으로 나가는 건 자살이나 다름없어.","JPN":"現在のCSEレベルを考慮すると、一般人が装備なしで外に出るのは自殺行為同然だ。","ENG":"With current CSE levels, any non-Counter going out there is suicide.","TWN":"考量到目前的CSE等級，一般人直接出去就跟自殺沒兩樣。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잠깐, 잔여 이터니움을 활용했다니?","JPN":"待て、残りのエタニウムを活用だと？","ENG":"Wait. What do you mean you used the remaining Eternium?","TWN":"等等，運用剩餘的永恆之金？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 선로전환기는 어쩌란 말이야? 저게 멈추면 전부 죽는다고!","JPN":"じゃあ線路転換器はどうするんだ？　あれが止まったらみんな死ぬんだぞ！","ENG":"Then what about the Track Switcher? If that stalls, we all die!","TWN":"那線路轉換器要怎麼辦？要是那個停下來，所有人都會死！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"현 상황에선 가장 합리적인 방안이다.","JPN":"今の状況ではもっとも合理的な判断だ。","ENG":"Given the situation, it's the most rational measure.","TWN":"這是目前情況下最合理的方案。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"네가 팀의 리더라면 이성적인 판단을 내리도록.","JPN":"あなたがチームのリーダーなら、理性的な判断を下せ。","ENG":"If you're the team lead, make the dispassionate call.","TWN":"如果你是隊長，就做出理性的判斷吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……젠장. 분수에 맞지도 않는 일을 맡아버렸군.","JPN":"……くそ、身の丈に合わない仕事を引き受けちまったもんだ。","ENG":"...Damn it. Took a job way out of my depth.","TWN":"……糟糕，接下了根本不合乎分寸的工作。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잔여 이터니움으로 얼마나 더 버틸 수 있지?","JPN":"残りのエタニウムで、あとどれぐらい耐えられる？","ENG":"How long can we hold with what Eternium we've got?","TWN":"用剩餘的永恆之金可以再撐多久？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"반나절을 버티면 기적이겠지.","JPN":"半日持てば奇跡といえるだろう。","ENG":"If we last half a day, call it a miracle.","TWN":"能撐半天就算是奇蹟了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"유서 쓸 시간으로는 과하고, 상황을 타개하기에는 짧군.","JPN":"遺書を書くには長すぎるし、状況を打開するには短すぎる時間だな。","ENG":"Too long for a last will, too short to break the deadlock.","TWN":"這時間要拿來寫遺書太長，要搞定情況又太短。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"결국 그때처럼…….","JPN":"結局、あの時のように……","ENG":"It's just like that time in the end...","TWN":"最終就只能……"},"stage":{"bg":"MAINSTREAM_805","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"기적을 바라는 수밖에 없겠어.","JPN":"奇跡に頼るしかないんだな。","ENG":"All we can do is pray for a miracle.","TWN":"像那時候一樣盼望奇蹟出現了。"},"stage":{"bg":"MAINSTREAM_805","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};